async (params, browser) => {
  // Open reviews page
  await browser.open(`${params.movie_url}/reviews`)

  // Wait for reviews to load
  await browser.waitForSelector('[class*=\'review-row\'], [class*=\'review_table\'], .review_table_row, [data-qa=\'review-item\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more reviews
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract critic reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[class*="review-row"], .review_table_row, [data-qa="review-item"], [class*="ReviewRow"]'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const criticEl = el.querySelector('[class*="critic-name"] a, [data-qa="review-critic"], [class*="critic"] a'); const pubEl = el.querySelector('[class*="publication"], [data-qa="review-publication"]'); const quoteEl = el.querySelector('[class*="review-text"], [data-qa="review-quote"], [class*="quote"]'); const dateEl = el.querySelector('[data-qa="review-date"], [class*="review-date"], time'); const freshEl = el.querySelector('[class*="fresh"], [class*="rotten"], [data-qa="review-icon"]'); const scoreEl = el.querySelector('[class*="score"], [data-qa="review-score"]'); let status = ''; if (freshEl) { const cls = freshEl.className || ''; if (cls.includes('fresh')) status = 'Fresh'; else if (cls.includes('rotten')) status = 'Rotten'; else status = freshEl.textContent.trim(); } reviews.push({ critic: criticEl ? criticEl.textContent.trim() : '', publication: pubEl ? pubEl.textContent.trim() : '', quote: quoteEl ? quoteEl.textContent.trim().substring(0, 500) : '', score: scoreEl ? scoreEl.textContent.trim() : '', status: status, date: dateEl ? dateEl.textContent.trim() : '' }); } const titleEl = document.querySelector('h1, [class*="scoreboard"] h1'); const tomatometerEl = document.querySelector('rt-button[slot="criticsScore"] rt-text, [data-qa="tomatometer"]'); return { title: titleEl ? titleEl.textContent.trim() : '', tomatometer: tomatometerEl ? tomatometerEl.textContent.trim() : '', scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
